window.ALT_HELPERS = {
  getProductsByCategory(categoryId) {
    return window.ALT_PRODUCTS.filter(p => p.categoryId === categoryId);
  },
  getCategoryById(id) {
    return window.ALT_CATEGORIES.find(c => c.id === id);
  },
  getProductBySku(sku) {
    return window.ALT_PRODUCTS.find(p => p.sku === sku);
  },
  formatPrice() {
    return null; // No price shown — Request Quote only
  },
  getTotalSkuCount() {
    return window.ALT_PRODUCTS.length;
  },
  getCategoryCount() {
    return window.ALT_CATEGORIES.length;
  },
  isPlaceholderImage(image) {
    return !image || image.indexOf('placeholder-product') !== -1;
  },
  getColorSiblings(product) {
    if (!product.colorGroup) return [];
    return window.ALT_PRODUCTS.filter(p => p.colorGroup === product.colorGroup);
  }
};
